FightScript:
if (PlayerInfo.Lucky<40)
        {
            return;
        }AddEvent("OnDiceValue", () =>
        {
                ValueDice.OnRoll += result => {
            result.CopyTo(new(result.Value+10,result.Bonus));
            };
        });
AddEvent("OnDiceCheck", () =>
        {

                CheckDice.OnRoll += result => {
 result.CopyTo(new( (result.Value-10),result.Bonus));
            };
        });

if (PlayerInfo.Perceive<40)
        {
            return;
        }AddEvent("StartRound",() => {SetStatus("Self");foreach (var item in Object)
        {
            if (GetStatus.ContainsKey(item))
            {
                item.CurHp = GetStatus[item]["CurHp"];
                item.MaxHp = GetStatus[item]["MaxHp"];
            }
            else
            {
                GetStatus[item] = new Dictionary<string, int>
                {
                    { "CurHp", item.CurHp },
                    { "MaxHp", item.MaxHp },
                };
            }
            AddBuff(DataId.buff_impregnable,"1");
        };});

if (PlayerInfo.SpecialVars.ContainsKey(DataId.blessing_35) ||PlayerInfo.enemylevel==4)
        {
            return;
        }
        ChangeDynamicVar("liveCount", "1");
        AddEvent("Resurrection",()=> {
            if (!PlayerInfo.SpecialVars.ContainsKey(DataId.blessing_35))
            {

                if (Self.dynamicVariables["liveCount"]==0f)
                {
                    PlayerInfo.SpecialVars[DataId.blessing_35] = "1";
                EscapeFight();
                }

            }
        });

AddEvent("FightStart", () => {
            Vars["ThisCount"] = (int.Parse(Vars.GetValueOrDefault("ThisCount", "0")) + 1).ToString();
            if (int.Parse(Vars["ThisCount"]) < 4)
            {
                ChangeMaxHp("-4");
            }
            AddEvent("Escape", () =>
            {
                if (int.Parse(Vars["ThisCount"]) >=3)
                {
                    for (int i = 0; i < 3; i++)
                    {
                        PlayerInfo.AddBless(DataId.blessing_6);
                    PlayerInfo.AddBless(DataId.blessing_20);
                    }

                    PlayerInfo.RemoveBless(DataId.blessing_36);
                }
            });
            AddEvent("Win",()=> {
                if (int.Parse(Vars["ThisCount"]) >=3)
                {
                    for (int i = 0; i < 3; i++)
                    {
                        PlayerInfo.AddBless(DataId.blessing_6);
                    PlayerInfo.AddBless(DataId.blessing_20);
                    }

                    PlayerInfo.RemoveBless(DataId.blessing_36);
                }
            });
             });

if (PlayerInfo.enemylevel==4)
        {
            return;
        }
        ChangeDynamicVar("liveCount", "999");
        AddEvent("Dead",()=> {

                if (Self.dynamicVariables["liveCount"]==1f)
                {
                EscapeFight();
                }

        });
